<?php
namespace Tests\Feature;use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use LogicException;use Tests\TestCase;
class ItemInstanceSchemaTest extends TestCase{use RefreshDatabase;private function item(){return Item::create(['code'=>'unique_sword','name'=>'Espada única','item_type'=>'equipment','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);}public function test_schema_indexes_defaults_and_restrict_relations(){$this->assertTrue(Schema::hasColumns('item_instances',['uuid','origin_type','origin_id','origin_unit_index','refinement_level']));$this->assertTrue(Schema::hasTable('item_instance_events'));$indexes=collect(DB::select('SHOW INDEX FROM item_instances'))->pluck('Key_name');$this->assertContains('item_instances_uuid_unique',$indexes);$this->assertContains('item_instances_origin_unit_unique',$indexes);$rules=DB::select("SELECT DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME IN ('item_instances','item_instance_events')");foreach($rules as $rule)$this->assertSame('RESTRICT',$rule->DELETE_RULE);}public function test_identity_origin_and_events_are_immutable_by_model(){$character=Character::factory()->for(User::factory())->create();$item=$this->item();$instance=ItemInstance::create(['uuid'=>'11111111-1111-5111-8111-111111111111','character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>0,'status'=>'available','origin_type'=>'legacy_inventory','origin_id'=>10,'origin_unit_index'=>1,'acquired_at'=>now()]);$this->assertSame(0,$instance->refinement_level);$instance->uuid='22222222-2222-5222-8222-222222222222';try{$instance->save();$this->fail();}catch(LogicException $e){}$event=ItemInstanceEvent::create(['item_instance_id'=>$instance->id,'operation_uuid'=>'33333333-3333-5333-8333-333333333333','event_type'=>ItemInstanceEventType::IMPORTED_FROM_LEGACY_INVENTORY,'source_type'=>'legacy_inventory','source_id'=>10,'occurred_at'=>now(),'created_at'=>now()]);try{$event->update(['metadata'=>['x'=>1]]);$this->fail();}catch(LogicException $e){}try{$event->delete();$this->fail();}catch(LogicException $e){}}public function test_birth_source_and_database_uniqueness_are_enforced(){$character=Character::factory()->for(User::factory())->create();$item=$this->item();$instance=ItemInstance::create(['uuid'=>'44444444-4444-5444-8444-444444444444','character_id'=>$character->id,'item_id'=>$item->id,'refinement_level'=>0,'status'=>'available','origin_type'=>'legacy_inventory','origin_id'=>20,'origin_unit_index'=>1,'acquired_at'=>now()]);$this->expectException(LogicException::class);ItemInstanceEvent::create(['item_instance_id'=>$instance->id,'operation_uuid'=>'55555555-5555-5555-8555-555555555555','event_type'=>ItemInstanceEventType::IMPORTED_FROM_LEGACY_INVENTORY,'occurred_at'=>now(),'created_at'=>now()]);}}
